import { useState } from 'react';

const C = {
  bg: '#0B0F14',
  surface: '#0F1620',
  border: '#1F2A37',
  text: '#E5E7DB',
  muted: '#90A3AF',
  green: '#22C55E',
  red: '#EF4444',
  blue: '#60A5FA',
  amber: '#F59E0B',
  purple: '#A78BFA',
};
const font = "'JetBrains Mono', monospace";

// Prediction markets data loaded from API — empty until connected
const EVENTS = [];

const CATEGORIES = ['All', 'Politics', 'Economics', 'Sports', 'Tech'];

const categoryColor = (cat) => {
  if (cat === 'Politics') return C.purple;
  if (cat === 'Economics') return C.amber;
  if (cat === 'Sports') return C.green;
  if (cat === 'Tech') return C.blue;
  return C.muted;
};

export default function PredictionMarkets() {
  const [filter, setFilter] = useState('All');
  const [selected, setSelected] = useState(null);
  const [amounts, setAmounts] = useState({});
  const [positions, setPositions] = useState({});

  const visible = filter === 'All' ? EVENTS : EVENTS.filter(e => e.category === filter);

  const handleBuy = (id, side) => {
    const amt = parseFloat(amounts[id] || 0);
    if (!amt || amt <= 0) return;
    setPositions(prev => ({
      ...prev,
      [id]: { side, amount: amt, filled: true },
    }));
    setAmounts(prev => ({ ...prev, [id]: '' }));
  };

  return (
    <div style={{ background: C.bg, minHeight: '100vh', fontFamily: font, padding: 24, color: C.text }}>
      <div style={{ maxWidth: 1100, margin: '0 auto' }}>
        {/* Header */}
        <div style={{ marginBottom: 24 }}>
          <h1 style={{ fontSize: 22, fontWeight: 700, color: C.text, margin: 0 }}>Prediction Markets</h1>
          <p style={{ color: C.muted, fontSize: 13, margin: '4px 0 0' }}>Trade event contracts. Prices reflect implied probability.</p>
        </div>

        {/* Filter tabs */}
        <div style={{ display: 'flex', gap: 8, marginBottom: 24 }}>
          {CATEGORIES.map(cat => (
            <button
              key={cat}
              onClick={() => setFilter(cat)}
              style={{
                background: filter === cat ? C.blue + '22' : C.surface,
                border: `1px solid ${filter === cat ? C.blue : C.border}`,
                color: filter === cat ? C.blue : C.muted,
                borderRadius: 6,
                padding: '5px 14px',
                fontSize: 13,
                cursor: 'pointer',
                fontFamily: font,
                transition: 'all 0.15s',
              }}
            >
              {cat}
            </button>
          ))}
        </div>

        {/* Card grid */}
        {visible.length === 0 && (
          <div style={{ textAlign: 'center', padding: '48px 0', color: C.muted, fontSize: 14, fontFamily: font }}>
            No prediction markets available. Connecting to data feed...
          </div>
        )}
        <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fill, minmax(320px, 1fr))', gap: 16 }}>
          {visible.map(event => {
            const isSelected = selected === event.id;
            const pos = positions[event.id];
            return (
              <div
                key={event.id}
                onClick={() => setSelected(isSelected ? null : event.id)}
                style={{
                  background: C.surface,
                  border: `1px solid ${isSelected ? C.blue : C.border}`,
                  borderRadius: 10,
                  padding: 16,
                  cursor: 'pointer',
                  transition: 'border-color 0.15s, box-shadow 0.15s',
                  boxShadow: isSelected ? `0 0 0 1px ${C.blue}44` : 'none',
                }}
              >
                {/* Category badge */}
                <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'flex-start', marginBottom: 12 }}>
                  <span style={{
                    fontSize: 10,
                    fontWeight: 700,
                    color: categoryColor(event.category),
                    background: categoryColor(event.category) + '18',
                    border: `1px solid ${categoryColor(event.category)}44`,
                    borderRadius: 6,
                    padding: '2px 8px',
                    textTransform: 'uppercase',
                    letterSpacing: 1,
                  }}>
                    {event.category}
                  </span>
                  {pos && (
                    <span style={{ fontSize: 10, color: pos.side === 'yes' ? C.green : C.red, background: (pos.side === 'yes' ? C.green : C.red) + '18', borderRadius: 6, padding: '2px 8px' }}>
                      {pos.side === 'yes' ? '▲ YES' : '▼ NO'} ${pos.amount}
                    </span>
                  )}
                </div>

                {/* Question */}
                <p style={{ fontSize: 14, fontWeight: 600, color: C.text, margin: '0 0 14px', lineHeight: 1.5 }}>
                  {event.question}
                </p>

                {/* Yes/No probability bars */}
                <div style={{ marginBottom: 12 }}>
                  <div style={{ display: 'flex', justifyContent: 'space-between', marginBottom: 4 }}>
                    <span style={{ fontSize: 11, color: C.green }}>YES {Math.round(event.yes * 100)}¢</span>
                    <span style={{ fontSize: 11, color: C.red }}>NO {Math.round(event.no * 100)}¢</span>
                  </div>
                  <div style={{ height: 8, background: C.border, borderRadius: 6, overflow: 'hidden', display: 'flex' }}>
                    <div style={{ width: `${event.yes * 100}%`, background: C.green, borderRadius: '4px 0 0 4px', transition: 'width 0.25s' }} />
                    <div style={{ width: `${event.no * 100}%`, background: C.red, borderRadius: '0 4px 4px 0', transition: 'width 0.25s' }} />
                  </div>
                </div>

                {/* Volume & expiry */}
                <div style={{ display: 'flex', justifyContent: 'space-between', fontSize: 11, color: C.muted }}>
                  <span>Vol: <span style={{ color: C.text }}>{event.volume}</span></span>
                  <span>Exp: <span style={{ color: C.text }}>{event.expiry}</span></span>
                </div>

                {/* Expanded order panel */}
                {isSelected && (
                  <div
                    style={{ marginTop: 16, paddingTop: 16, borderTop: `1px solid ${C.border}` }}
                    onClick={e => e.stopPropagation()}
                  >
                    <p style={{ fontSize: 11, color: C.muted, margin: '0 0 8px' }}>Amount (USD)</p>
                    <input
                      type="number"
                      min="1"
                      placeholder="e.g. 50"
                      value={amounts[event.id] || ''}
                      onChange={e => setAmounts(prev => ({ ...prev, [event.id]: e.target.value }))}
                      style={{
                        width: '100%',
                        background: C.bg,
                        border: `1px solid ${C.border}`,
                        borderRadius: 6,
                        color: C.text,
                        fontFamily: font,
                        fontSize: 13,
                        padding: '7px 10px',
                        marginBottom: 12,
                        boxSizing: 'border-box',
                        outline: 'none',
                      }}
                    />
                    <div style={{ display: 'flex', gap: 8 }}>
                      <button
                        onClick={() => handleBuy(event.id, 'yes')}
                        style={{
                          flex: 1,
                          background: C.green + '22',
                          border: `1px solid ${C.green}`,
                          color: C.green,
                          borderRadius: 6,
                          padding: '8px 0',
                          fontSize: 13,
                          fontWeight: 700,
                          cursor: 'pointer',
                          fontFamily: font,
                        }}
                      >
                        Buy YES
                      </button>
                      <button
                        onClick={() => handleBuy(event.id, 'no')}
                        style={{
                          flex: 1,
                          background: C.red + '22',
                          border: `1px solid ${C.red}`,
                          color: C.red,
                          borderRadius: 6,
                          padding: '8px 0',
                          fontSize: 13,
                          fontWeight: 700,
                          cursor: 'pointer',
                          fontFamily: font,
                        }}
                      >
                        Buy NO
                      </button>
                    </div>
                  </div>
                )}
              </div>
            );
          })}
        </div>

        {visible.length === 0 && (
          <div style={{ textAlign: 'center', padding: 64, color: C.muted, fontSize: 13 }}>
            No events in this category.
          </div>
        )}
      </div>
    </div>
  );
}
